import{C as a,o as p,c as s,E as e,a2 as i,j as g,a5 as n,a6 as c}from"./chunks/framework.CkaEw-3u.js";const l={class:"reference-parameter-grid reference-parameter-grid-2"},b=JSON.parse('{"title":"スクリプティング設定 (Scripting Settings)","description":"Luaスクリプトの有効化とスクリプト本文の設定、実行制限の詳細","frontmatter":{"title":"スクリプティング設定 (Scripting Settings)","description":"Luaスクリプトの有効化とスクリプト本文の設定、実行制限の詳細","pageClass":"reference-page","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/reference/reference-scripting-settings.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"ja_JP"}],["meta",{"property":"og:title","content":"スクリプティング設定 (Scripting Settings) | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Luaスクリプトの有効化とスクリプト本文の設定、実行制限の詳細"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/reference/reference-scripting-settings.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"property":"og:image:type","content":"image/png"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"スクリプティング設定 (Scripting Settings) | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Luaスクリプトの有効化とスクリプト本文の設定、実行制限の詳細"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"reference/reference-scripting-settings.md","filePath":"reference/reference-scripting-settings.md"}'),m={name:"reference/reference-scripting-settings.md"},S=Object.assign(m,{setup(h){const r={standardPreset:{image:"/image/inspector_scripting_standard.webp",alt:"通常プリセットのScriptingページ",label:"通常プリセット · Scriptingページ",sourceWidth:615,sourceHeight:454,top:0,bottom:454},scriptingPreset:{image:"/image/inspector_scripting_preset.webp",alt:"Mug Typography ScriptingプリセットのGlobalページ",label:"Scriptingプリセット · Globalページ",sourceWidth:609,sourceHeight:457,top:0,bottom:457}};return(u,t)=>{const d=a("ReferenceOverview"),o=a("InspectorCrop");return p(),s("div",null,[e(d,{eyebrow:"PARAMETER REFERENCE",title:"Scripting Settings",description:"Lua 5.4スクリプトによるプロシージャルなアニメーション制御を設定します。",items:[{icon:"▤",title:"Inspector",description:"プリセットごとの表示位置",href:"#インスペクタでの表示"},{icon:"🎬",title:"Edit Page",description:"Generator使用時の注意",href:"#edit-pageでの使用上の注意"},{icon:"⚠️",title:"制限事項",description:"エラー時の挙動と実行制限",href:"#エラー時の挙動と実行制限"}]}),t[0]||(t[0]=i('<p>通常の2D / 3D / Liteプリセットでは、インスペクタの <strong>Page</strong> で <code>Scripting</code> を選択すると表示されるページです。専用の<code>Mug Typography Scripting</code>プリセットでは、同じ設定が<strong>Globalページ内</strong>に表示されます。機能の概要と作例は「<a href="/mug-typography-docs/features/feature-scripting.html">Luaスクリプトで動かす（Scripting）</a>」を参照してください。</p><div class="info custom-block"><p class="custom-block-title">Mug Typography Scriptingプリセット</p><p>Character SettingsとPart Settingsを省略し、最大128文字・512パーツをLuaから制御する用途に特化したプリセットです。Global設定と3DのCamera設定は利用できますが、Character / Part選択モード、Copy / Paste、文字・パーツを対象とするRandomizeは表示されません。</p></div><h2 id="インスペクタでの表示" tabindex="-1">インスペクタでの表示 <a class="header-anchor" href="#インスペクタでの表示" aria-label="Permalink to &quot;インスペクタでの表示&quot;">​</a></h2><p>通常プリセットでは<strong>Pageを<code>Scripting</code>へ切り替えて</strong>設定します。専用のMug Typography Scriptingプリセットでは、同じScriptingグループが<strong>Globalページ内に常時表示</strong>されます。</p>',4)),g("div",l,[e(o,n(c(r.standardPreset)),null,16),e(o,n(c(r.scriptingPreset)),null,16)]),t[1]||(t[1]=i('<h2 id="パラメーター" tabindex="-1">パラメーター <a class="header-anchor" href="#パラメーター" aria-label="Permalink to &quot;パラメーター&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Script Enabled</strong></td><td>レンダリング時にScript TextのLuaスクリプトを実行します。ONにするとスクリプトが毎フレーム評価されるため、ホストのフレームキャッシュは効かなくなります。</td><td>OFF</td></tr><tr><td><strong>Script Text</strong></td><td>実行するLua 5.4スクリプト本文（複数行）。<code>OnInitialize(ctx)</code> / <code>OnPreLayout(ctx)</code> / <code>OnLayout(ctx)</code> を定義します。</td><td><code>OnLayout</code> の雛形</td></tr><tr><td><strong>Copy Script</strong></td><td>Script Textの内容をOSのクリップボードへコピーします。MT Simや外部エディタへ戻すときに使用します。</td><td>—</td></tr><tr><td><strong>Paste Script</strong></td><td>OSのクリップボードにあるテキストでScript Textを置き換えます。ホストのUndoで元に戻せます。</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">スクリプトの開発はVSCode拡張で</p><p>Script Text欄はスクリプトの「供給口」であり、エディタとしての支援機能はありません。開発・デバッグには配布ZIP同梱のVSCode拡張「Mug Typography Scripting Simulator」(MT Sim) を使い、MT SimのCopy ScriptとプラグインのPaste Scriptで完成したスクリプトを移す運用を推奨します。</p></div><h2 id="スクリプトから制御できるもの" tabindex="-1">スクリプトから制御できるもの <a class="header-anchor" href="#スクリプトから制御できるもの" aria-label="Permalink to &quot;スクリプトから制御できるもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>コールバック</th><th>書き込み先</th></tr></thead><tbody><tr><td><code>OnPreLayout</code></td><td><code>ctx.global</code>（テキスト・フォントサイズ・字送り・行間・整列・縦書き・位置・回転・スケール・塗り・グラデーション・ストローク・影など）、<code>ctx.camera</code>（3D / Scriptingプリセット）</td></tr><tr><td><code>OnLayout</code></td><td><code>ctx.chars[index]</code> / <code>ctx.parts[index]</code>（位置・回転・スケール・ピボット・個別色・個別ストローク・個別影・3D姿勢）、<code>ctx.bounding_box</code>、<code>ctx.output</code>（Write On）</td></tr></tbody></table><p>読み取り専用の情報として <code>ctx.time</code>（秒）、<code>ctx.frame</code>、<code>ctx.timeline</code>（クリップ長・進捗）、<code>ctx.font</code>、<code>ctx.meta</code>（APIレベル・プリセット能力・上限値）、文字・パーツの <code>geometry</code>（実測ジオメトリ）が利用できます。完全な仕様は配布ZIP同梱の <code>scripting-simulator/docs/scripting_api.md</code> を参照してください。</p><h2 id="edit-pageでの使用上の注意" tabindex="-1">Edit Pageでの使用上の注意 <a class="header-anchor" href="#edit-pageでの使用上の注意" aria-label="Permalink to &quot;Edit Pageでの使用上の注意&quot;">​</a></h2><p><strong>Generatorプリセットでは、クリップの分割や0フレームより前への拡張に制限があります。</strong></p><p>これらの操作を行うと、DaVinci Resolveから正しい時間情報が渡されず、<code>ctx.time</code>を使うアニメーションが崩れる場合があります。</p><p>操作を避けるか、Adjustment Clip（調整クリップ）へFilters側のMug Typographyプリセットを適用してください。</p><h2 id="エラー時の挙動と実行制限" tabindex="-1">エラー時の挙動と実行制限 <a class="header-anchor" href="#エラー時の挙動と実行制限" aria-label="Permalink to &quot;エラー時の挙動と実行制限&quot;">​</a></h2><p>スクリプトのエラーは描画を止めません。コールバック内のどこかでエラーが起きると、<strong>そのコールバックによる変更全体が破棄され</strong>、元の値で描画が続行されます（コールバック単位の原子性）。</p><table tabindex="0"><thead><tr><th>失敗箇所</th><th>結果</th></tr></thead><tbody><tr><td>スクリプトロード</td><td>スクリプト全体を実行しない</td></tr><tr><td><code>OnInitialize</code></td><td>storageを破棄</td></tr><tr><td><code>OnPreLayout</code></td><td>インスペクタ由来の値で描画し、<code>OnLayout</code> もスキップ</td></tr><tr><td><code>OnLayout</code></td><td>Baseから生成された未変更の値で描画</td></tr></tbody></table><p>暴走防止のため、1コールバック呼び出しあたり <strong>5,000,000命令</strong>、メモリ <strong>128MiB</strong> の上限があります。メモリは必要な分だけ確保されます。上限を超えたコールバックはエラーとして扱われ、上記のとおりロールバックされます。</p><div class="warning custom-block"><p class="custom-block-title">制限事項</p><ul><li>スクリプトが書き込んだ値はそのフレームの描画にのみ使われ、インスペクタやキーフレームへは書き戻されません</li><li>モーフアニメーションの実行中（To Textによる変形中）はスクリプトのコールバックはスキップされます</li><li>パスジオメトリ自体の書き換えや、外部 <code>.lua</code> ファイルの読み込みには対応していません</li></ul></div>',15))])}}});export{b as __pageData,S as default};
